                        <circle cx="93" cy="35" r="2" fill="currentColor" class="text-gray-300 dark:text-gray-600"><animate attributeName="opacity" values="0.2;0.8;0.2" dur="2.4s" begin="0.4s" repeatCount="indefinite"/></circle>
